package main

import "fmt"

func main() {
    // Closure as factory
    nextId := func() func() int {
        id := 0
        return func() int {
            id++
            return id
        }
    }()

    fmt.Println(nextId()) // 1
    fmt.Println(nextId()) // 2
    fmt.Println(nextId()) // 3

    // Closure with params
    addTo := func(base int) func(int) int {
        return func(x int) int {
            return base + x
        }
    }

    addFive := addTo(5)
    fmt.Println(addFive(10)) // 15
}
